"""Configuration management for ctxcli.

Handles profile configuration, tools caching, and TTL management.
Completely independent from ctxctl configuration.
"""

from datetime import datetime
from pathlib import Path
from typing import Any

import yaml
from pydantic import BaseModel, Field

from context_surfaces.cli.ctxcli.constants import (
    CONFIG_DIR,
    CONFIG_FILE,
    DEFAULT_MCP_URL,
    DEFAULT_PROFILE_NAME,
    TOOLS_CACHE_TTL_HOURS,
)


class ToolSchema(BaseModel):
    """Schema for a cached MCP tool."""

    name: str
    description: str = ""
    input_schema: dict[str, Any] = Field(default_factory=dict)


class ToolsCache(BaseModel):
    """Cache for MCP tools with TTL."""

    fetched_at: datetime = Field(default_factory=datetime.now)
    tools: list[ToolSchema] = Field(default_factory=list)

    def is_expired(self) -> bool:
        """Check if the cache has expired (older than TTL)."""
        from datetime import timedelta

        age = datetime.now() - self.fetched_at
        return age > timedelta(hours=TOOLS_CACHE_TTL_HOURS)


class ProfileConfig(BaseModel):
    """Configuration for a single ctxcli profile."""

    mcp_url: str = DEFAULT_MCP_URL
    agent_key: str = ""
    tools_cache: ToolsCache | None = None

    def is_initialized(self) -> bool:
        """Check if the profile has been initialized."""
        return bool(self.agent_key)

    def has_cached_tools(self) -> bool:
        """Check if the profile has cached tools."""
        return self.tools_cache is not None and len(self.tools_cache.tools) > 0


class CtxcliConfig(BaseModel):
    """Root configuration for ctxcli."""

    default_profile: str = DEFAULT_PROFILE_NAME
    profiles: dict[str, ProfileConfig] = Field(default_factory=lambda: {DEFAULT_PROFILE_NAME: ProfileConfig()})


class ConfigManager:
    """Manages ctxcli configuration.

    Configuration is stored at ~/.config/ctxcli/config.yaml
    Completely independent from ctxctl configuration.
    """

    def __init__(self, config_path: Path | None = None) -> None:
        """Initialize the config manager.

        Args:
            config_path: Optional custom config file path
        """
        self.config_dir = config_path.parent if config_path else CONFIG_DIR
        self.config_file = config_path or CONFIG_FILE
        self._config: CtxcliConfig | None = None

    def _ensure_config_dir(self) -> None:
        """Ensure the config directory exists."""
        self.config_dir.mkdir(parents=True, exist_ok=True)

    def load_config(self) -> CtxcliConfig:
        """Load configuration from file.

        Returns:
            CtxcliConfig instance
        """
        if self._config is not None:
            return self._config

        if not self.config_file.exists():
            self._config = CtxcliConfig()
            return self._config

        try:
            with open(self.config_file) as f:
                data = yaml.safe_load(f) or {}
            self._config = CtxcliConfig.model_validate(data)
        except Exception:
            # If config is corrupted, start fresh
            self._config = CtxcliConfig()

        return self._config

    def save_config(self, config: CtxcliConfig | None = None) -> None:
        """Save configuration to file.

        Args:
            config: Config to save. Uses cached config if not provided.
        """
        self._ensure_config_dir()

        if config is not None:
            self._config = config

        if self._config is None:
            self._config = CtxcliConfig()

        data = self._config.model_dump(mode="json")

        with open(self.config_file, "w") as f:
            yaml.safe_dump(data, f, default_flow_style=False, sort_keys=False)

    def get_profile(self, profile_name: str | None = None) -> ProfileConfig:
        """Get a profile configuration.

        Args:
            profile_name: Profile name. Uses default if not provided.

        Returns:
            ProfileConfig instance

        Raises:
            KeyError: If profile doesn't exist
        """
        config = self.load_config()
        name = profile_name or config.default_profile

        if name not in config.profiles:
            raise KeyError(f"Profile '{name}' not found")

        return config.profiles[name]

    def set_profile(self, profile_name: str, profile: ProfileConfig) -> None:
        """Set a profile configuration.

        Args:
            profile_name: Profile name
            profile: Profile configuration
        """
        config = self.load_config()
        config.profiles[profile_name] = profile
        self.save_config(config)

    def is_initialized(self, profile_name: str | None = None) -> bool:
        """Check if a profile is initialized.

        Args:
            profile_name: Profile name. Uses default if not provided.

        Returns:
            True if the profile is initialized
        """
        try:
            profile = self.get_profile(profile_name)
            return profile.is_initialized()
        except KeyError:
            return False

